verify-env-print.script:
test -f reports/current-env.txt || {
  echo '[ERROR] missing reports/current-env.txt'
  exit 1
}
test -f reports/expected-env.txt || {
  echo '[ERROR] missing reports/expected-env.txt'
  exit 1
}
grep -F 'FLOW_MESSAGE=flow-env-print' reports/current-env.txt || {
  echo '[ERROR] FLOW_MESSAGE not found in captured env'
  exit 1
}
grep -F 'FLOW_SCOPE=integration' reports/expected-env.txt || {
  echo '[ERROR] FLOW_SCOPE marker mismatch'
  exit 1
}
grep -F 'CI_JOB_NAME=print-current-env' reports/expected-env.txt || {
  echo '[ERROR] CI_JOB_NAME marker mismatch'
  exit 1
}
